stylesheet:
QWidget {
    background: #0a1018;
    color: #c8daf5;
    font-family: "JetBrains Sans", "Segoe UI Variable", "Segoe UI", "Arial", "Noto Sans", sans-serif;
    font-size: 10pt;
}
#WindowShell {
    background: transparent;
}
QStackedWidget, QStackedWidget > QWidget, QWidget#PagesShell, QStackedWidget#PagesStack {
    background: transparent;
}
QWidget[class="pageRoot"], QWidget[class="pageCanvas"] {
    background: transparent;
}
QLabel {
    background: transparent;
}
#RootFrame {
    background: #0e1620;
    border: 1px solid #1e2a3a;
    border-radius: 16px;
}
#TitleBar {
    background: #0e1620;
    border: none;
    border-top-left-radius: 16px;
    border-top-right-radius: 16px;
}
#Sidebar {
    background: #0e1620;
    border-bottom-left-radius: 16px;
}
#Content {
    background: transparent;
    border: none;
}
#ContentSurface {
    background: qlineargradient(x1:0, y1:1, x2:1, y2:0, stop:0 #0a1018, stop:0.62 #0e1620, stop:1 #142030);
    border-top: 1px solid #1e2a3a;
    border-left: 1px solid #1e2a3a;
    border-top-left-radius: 18px;
    border-top-right-radius: 0px;
    border-bottom-left-radius: 0px;
    border-bottom-right-radius: 16px;
}
QDialog#AppDialogWindow {
    background: transparent;
    border: none;
}
#DialogRoot {
    background: #121a28;
    border: 1px solid #24354a;
    border-radius: 12px;
}
#DialogTitleBar {
    background: transparent;
    border: none;
    border-top-left-radius: 12px;
    border-top-right-radius: 12px;
}
#DialogBody {
    background: transparent;
}
#SettingsScroll, #SettingsCanvas, #SettingsScroll QWidget#qt_scrollarea_viewport {
    background: transparent;
    border: none;
}
QFrame[class="settingsSection"] {
    background: #121a28;
    border: 1px solid #24354a;
    border-radius: 14px;
}
#LoadingOverlay {
    background: rgba(10, 16, 24, 0.6);
}
#LoadingCard {
    background: #121a28;
    border: 1px solid #2a4560;
    border-radius: 16px;
}
QFrame[class="card"] {
    background: qlineargradient(x1:0, y1:1, x2:1, y2:0, stop:0 #0e1620, stop:0.68 #121a28, stop:1 #182238);
    border: 1px solid #1e2a3a;
    border-radius: 16px;
}
QFrame[class="modHero"] {
    background: qlineargradient(x1:0, y1:0, x2:1, y2:1, stop:0 #142030, stop:1 #0e1620);
    border: 1px solid #2a4058;
    border-radius: 16px;
}
QFrame[class="modCard"] {
    background: #121a28;
    border: 1px solid #24354a;
    border-radius: 16px;
}
QFrame#NotificationsPopup {
    background: #121a28;
    border: 1px solid #2a4058;
    border-radius: 14px;
}
QFrame[class="notificationCard"] {
    background: #182238;
    border: 1px solid #2a4058;
    border-radius: 12px;
}
QScrollArea#NotificationsScroll, QWidget#NotificationsCanvas {
    background: transparent;
    border: none;
}
QFrame[class="modIconWrap"] {
    background: #1a2640;
    border: 1px solid #2a4560;
    border-radius: 16px;
}
QLabel[class="title"] {
    font-size: 13pt;
    font-weight: 700;
    color: #e8f0ff;
}
#DashboardTitle {
    padding: 0px;
    margin: 0px;
}
#DashboardPowerBlock {
    background: transparent;
}
QLabel[class="muted"] {
    color: #8aa0c0;
}
QLabel[class="modHint"] {
    color: #9ab0d0;
}
QLabel[class="modState"] {
    color: #e8f0ff;
    background: #1a2640;
    border: 1px solid #2a4560;
    border-radius: 12px;
    padding: 6px 12px;
    font-weight: 600;
}
QLabel[class="modState"][state="enabled"] {
    background: rgba(60, 160, 100, 0.16);
    border: 1px solid #4d8b67;
    color: #a8efc1;
}
QLabel[class="modState"][state="installed"] {
    background: rgba(70, 120, 200, 0.16);
    border: 1px solid #6080c0;
    color: #c8dcff;
}
QLabel[class="modState"][state="not installed"] {
    background: rgba(100, 120, 150, 0.08);
    border: 1px solid #405070;
    color: #9ab0d0;
}
QLabel[class="modMeta"] {
    color: #8aa0c0;
    background: #161e2e;
    border: 1px solid #24354a;
    border-radius: 12px;
    padding: 6px 12px;
}
#ModsSummaryChip, #ModsEnabledChip {
    border-radius: 11px;
}
#ModStateBadge, #ModMetaChip {
    border-radius: 12px;
}
QLabel[class="modBody"] {
    color: #c8daf5;
    line-height: 1.3em;
}
#ModsScroll, #ModsCanvas, #ComponentsScroll, #ComponentsCanvas {
    background: transparent;
    border: none;
}
QToolButton[class="nav"] {
    min-width: 46px;
    min-height: 46px;
    max-width: 46px;
    max-height: 46px;
    border-radius: 12px;
    border: 1px solid transparent;
    background: transparent;
}
QToolButton[class="nav"]:hover {
    background: #1a2640;
    border: 1px solid #2a4560;
}
QToolButton[class="nav"]:checked {
    background: #2a4058;
    border: 1px solid #6080c0;
}
QToolButton[class="window"] {
    min-width: 26px;
    min-height: 26px;
    max-width: 26px;
    max-height: 26px;
    border-radius: 12px;
    border: none;
    background: transparent;
    padding: 0px;
    margin: 0px;
}
QToolButton[class="window"][role="close"]:hover {
    background: rgba(80, 130, 200, 0.5);
}
QPushButton {
    background: #1a2640;
    border: 1px solid #2a4560;
    border-radius: 10px;
    padding: 8px 12px;
}
#LogsFilesShell {
    background: #0e1620;
    border: 1px solid #1e2a3a;
    border-radius: 16px;
}
QTabBar::tab {
    background: #0a1018;
    border: 1px solid #2a4058;
    border-radius: 8px;
    padding: 6px 16px;
    margin-right: 4px;
    color: #9ab0d0;
}
QTabBar::tab:selected {
    background: #4a7ac0;
    border-color: #6a9ae0;
    color: #ffffff;
}
QTabBar::tab:hover:!selected {
    background: #1a2640;
}
QPushButton[class="settingsSegment"] {
    background: #0a1018;
    border: 1px solid #2a4058;
    color: #9ab0d0;
}
QPushButton[class="settingsSegment"]:checked {
    background: #4a7ac0;
    color: #ffffff;
}
QToolButton[class="power"] {
    background: qlineargradient(x1:0, y1:0, x2:0, y2:1, stop:0 #5a8ad0, stop:0.48 #4a7ac0, stop:1 #3a5aa0);
    border: 2px solid #6a9ae0;
}
QToolButton[class="power"][state="off"] {
    background: qlineargradient(x1:0, y1:0, x2:0, y2:1, stop:0 #2a4058, stop:0.55 #1a2640, stop:1 #121e30);
    border: 2px solid #2a4560;
}
QLineEdit, QComboBox, QTextEdit, QTableWidget {
    background: #0a1018;
    border: 1px solid #2a4058;
    selection-background-color: #2a4560;
}
QCheckBox::indicator {
    border: 1px solid #506090;
    background: transparent;
}
QCheckBox::indicator:checked {
    border: 1px solid #6a9ae0;
    background: #4a7ac0;
}
QListWidget {
    background: #0a1018;
    border: 1px solid #2a4058;
}
QListWidget::item {
    background: #121a28;
    border: 1px solid #24354a;
}
QListWidget::item:selected {
    background: #2a4058;
    border: 1px solid #4a7ac0;
}
QHeaderView::section {
    background: #1a2640;
    color: #c8daf5;
}
QMenu {
    background: #121a28;
    border: 1px solid #2a4058;
}
QMenu::item:selected {
    background: #2a4058;
}
